PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (   id INTEGER PRIMARY KEY AUTOINCREMENT,   email TEXT NOT NULL UNIQUE,   full_name TEXT NOT NULL,   role TEXT NOT NULL CHECK (role IN ('customer', 'internal')),   company TEXT,   created_at TEXT DEFAULT CURRENT_TIMESTAMP );
CREATE TABLE packages (   id INTEGER PRIMARY KEY AUTOINCREMENT,   name TEXT NOT NULL,   destination TEXT NOT NULL,   country_region TEXT NOT NULL,   category TEXT NOT NULL,   duration_days INTEGER NOT NULL,   price_from_eur INTEGER NOT NULL,   physical_level TEXT NOT NULL,   luxury_level TEXT NOT NULL,   best_season TEXT NOT NULL,   ideal_for TEXT NOT NULL,   included TEXT NOT NULL,   not_included TEXT NOT NULL,   cancellation_policy TEXT NOT NULL,   short_description TEXT NOT NULL,   long_description TEXT NOT NULL,   highlights TEXT NOT NULL,   why_recommend TEXT NOT NULL,   why_not_recommend TEXT NOT NULL,   active INTEGER NOT NULL DEFAULT 1 );
CREATE TABLE package_commercials (   id INTEGER PRIMARY KEY AUTOINCREMENT,   package_id INTEGER NOT NULL,   internal_cost_eur INTEGER NOT NULL,   margin_amount_eur INTEGER NOT NULL,   margin_percent REAL NOT NULL,   commercial_priority TEXT NOT NULL CHECK (commercial_priority IN ('Low', 'Medium', 'High', 'Strategic')),   sales_argument TEXT NOT NULL,   internal_notes TEXT,   FOREIGN KEY (package_id) REFERENCES packages(id) );
DELETE FROM sqlite_sequence;
